214	// collector is a prometheus.Collector that reads a Source at scrape time and
215	// emits per-path const-metrics plus the placeholder FEC counters. Reading at
216	// scrape time (rather than mirroring into GaugeVecs on an update path) keeps the
217	// exposition consistent with the live telemetry with no duplicated state and no
218	// staleness window.
219	type collector struct {
220		src Source
221	
222		txBytes    *prometheus.Desc
223		rxBytes    *prometheus.Desc
224		loss       *prometheus.Desc
225		rtt        *prometheus.Desc
226		jitter     *prometheus.Desc
227		throughput *prometheus.Desc
228		up         *prometheus.Desc
229	
230		fecData          *prometheus.Desc
231		fecRepair        *prometheus.Desc
232		fecRecovered     *prometheus.Desc
233		fecUnrecoverable *prometheus.Desc
234		fecDataBytes     *prometheus.Desc
235		fecRepairBytes   *prometheus.Desc
236		fecResidualLoss  *prometheus.Desc
237	
238		sessionEstablished   *prometheus.Desc
239		sessionLastHandshake *prometheus.Desc
240	}
